import express from "express";
import path from "path";
import { createServer as createViteServer } from "vite";
import axios from "axios";

async function startServer() {
  const app = express();
  const PORT = 3000;

  app.use(express.json());

  // API proxy route to fetch public Google Sheet CSV
  app.get("/api/fetch-sheet", async (req, res) => {
    try {
      const { spreadsheetId, gid, sheetName, isPublished } = req.query;
      
      if (!spreadsheetId) {
        return res.status(400).json({ error: "spreadsheetId is required" });
      }

      let url = "";
      if (isPublished === 'true') {
        const gidParam = gid ? `&gid=${gid}` : "";
        url = `https://docs.google.com/spreadsheets/d/${spreadsheetId}/pub?output=csv${gidParam}`;
      } else if (sheetName) {
        url = `https://docs.google.com/spreadsheets/d/${spreadsheetId}/gviz/tq?tqx=out:csv&sheet=${encodeURIComponent(sheetName as string)}`;
      } else {
        const gidParam = gid ? `&gid=${gid}` : "";
        url = `https://docs.google.com/spreadsheets/d/${spreadsheetId}/export?format=csv${gidParam}`;
      }
      
      const response = await axios.get(url, { responseType: 'text' });
      res.setHeader('Content-Type', 'text/csv');
      res.send(response.data);
    } catch (error: any) {
      console.error("Error fetching sheet:", error.message);
      if (error.response && error.response.status === 401 || error.response?.status === 403) {
         return res.status(400).json({ error: "La hoja de cálculo no es pública o no se tienen permisos. Por favor asegúrate de que el enlace sea 'Cualquier persona con el enlace puede leer'." });
      }
      res.status(500).json({ error: "Error al descargar la hoja de cálculo. Revisa que el ID sea correcto y sea pública." });
    }
  });

  // Vite middleware for development
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), 'dist');
    app.use(express.static(distPath));
    app.get('*', (req, res) => {
      res.sendFile(path.join(distPath, 'index.html'));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`Server running on http://localhost:${PORT}`);
  });
}

startServer();
